import './App.css';

function App() {
  const items = [
  { id: 1, name: "Raket Yonex Astrox 100 ZZ", price: "50.000", category: "Badminton", img: "/astrox.jpg" },
  { id: 2, name: "Sepatu Bola Adidas F50", price: "120.000", category: "Football", img: "/f50.jpg" },
  { id: 3, name: "Dumbbell 10Kg", price: "30.000", category: "Fitness", img: "/dumbbell.jpg" },
];

  return (
    <div style={{ backgroundColor: '#f8f9fa', minHeight: '100vh', fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif" }}>
      {/* Navbar Modern */}
      <nav style={{ backgroundColor: '#ffffff', padding: '10px 40px', display: 'flex', justifyContent: 'space-between', alignItems: 'center', boxShadow: '0 2px 10px rgba(0,0,0,0.05)', position: 'sticky', top: 0, zIndex: 100 }}>
        <h1 style={{ color: '#007bff', margin: 0, fontSize: '24px', fontWeight: '800' }}>GEAR<span style={{color: '#333'}}>SHARE</span></h1>
        <div style={{ display: 'flex', gap: '20px', alignItems: 'center' }}>
          <input type="text" placeholder="Cari raket, tenda, atau sepatu..." style={{ padding: '10px 15px', borderRadius: '8px', border: '1px solid #eee', width: '300px', backgroundColor: '#f1f3f5' }} />
          <button style={{ background: 'none', border: 'none', fontWeight: '600', color: '#666', cursor: 'pointer' }}>Masuk</button>
          <button style={{ backgroundColor: '#007bff', color: 'white', padding: '10px 20px', borderRadius: '8px', border: 'none', fontWeight: 'bold', cursor: 'pointer' }}>Daftar</button>
        </div>
      </nav>

      {/* Main Content */}
      <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '40px 20px' }}>
        <div style={{ marginBottom: '30px' }}>
          <h2 style={{ color: '#212529', marginBottom: '8px', fontSize: '28px' }}>Sewa Alat Olahraga</h2>
          <p style={{ color: '#6c757d', margin: 0 }}>Temukan perlengkapan terbaik dari komunitas olahraga di sekitarmu.</p>
        </div>
        
        {/* Grid Daftar Alat */}
        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(250px, 1fr))', gap: '25px' }}>
          {items.map(item => (
            <div key={item.id} style={{ backgroundColor: '#fff', borderRadius: '15px', overflow: 'hidden', boxShadow: '0 10px 20px rgba(0,0,0,0.05)', border: '1px solid #f1f1f1', display: 'flex', flexDirection: 'column' }}>
              {/* Container Gambar agar ukurannya seragam */}
              <div style={{ width: '100%', height: '180px', overflow: 'hidden', backgroundColor: '#eee' }}>
                <img 
                  src={item.img} 
                  alt={item.name} 
                  style={{ width: '100%', height: '100%', objectFit: 'cover' }} 
                  onError={(e) => { e.target.src = "https://via.placeholder.com/250x180?text=Gambar+Tidak+Ada" }}
                />
              </div>

              <div style={{ padding: '20px', flexGrow: 1, display: 'flex', flexDirection: 'column', justifyContent: 'space-between' }}>
                <div>
                  <span style={{ fontSize: '11px', color: '#007bff', fontWeight: 'bold', textTransform: 'uppercase', letterSpacing: '1px' }}>{item.category}</span>
                  <h3 style={{ fontSize: '18px', margin: '8px 0', color: '#333', lineHeight: '1.4' }}>{item.name}</h3>
                  <p style={{ fontSize: '18px', color: '#212529', fontWeight: '800', margin: '10px 0' }}>Rp {item.price} <span style={{fontSize: '12px', color: '#999', fontWeight: '400'}}>/ hari</span></p>
                </div>
                
                <button style={{ width: '100%', marginTop: '15px', padding: '12px', backgroundColor: '#007bff', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', fontWeight: 'bold', transition: '0.2s' }}>
                  Sewa Sekarang
                </button>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

export default App;
